diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..f5b725a6dbad 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3506,6 +3506,53 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     return BinaryOperator::CreateMul(X, IncrementY);
   }

+  // or disjoint (shl (udiv X, C), D), (urem X, C)
+  //   --> add (mul (udiv X, C), (1<<D) - C), X
+  // or disjoint (mul (udiv X, C), K), (urem X, C)
+  //   --> add (mul (udiv X, C), K - C), X
+  // where K > C.
+  if (cast<PossiblyDisjointInst>(&I)->isDisjoint()) {
+    const APInt *DivC, *ShAmt, *MulK;
+    Value *X;
+    // Try to match Op as mul/shl of udiv X, DivC with multiplier K.
+    auto MatchDivMul = [&](Value *Op, Value *&X, const APInt *&C,
+                           APInt &K) -> bool {
+      if (match(Op, m_OneUse(m_Shl(m_OneUse(m_UDiv(m_Value(X), m_APInt(C))),
+                                    m_APInt(ShAmt))))) {
+        K = APInt(ShAmt->getBitWidth(), 1) << *ShAmt;
+        return true;
+      }
+      if (match(Op, m_OneUse(m_Mul(m_OneUse(m_UDiv(m_Value(X), m_APInt(C))),
+                                    m_APInt(MulK))))) {
+        K = *MulK;
+        return true;
+      }
+      return false;
+    };
+    APInt K;
+    const APInt *C;
+    Value *X0, *X1;
+    const APInt *RemC;
+    if (MatchDivMul(Op0, X0, C, K) &&
+        match(Op1, m_OneUse(m_URem(m_Specific(X0), m_APInt(RemC)))) &&
+        *C == *RemC && K.ugt(*C)) {
+      Value *DivCVal = ConstantInt::get(Ty, *C);
+      Value *Div = Builder.CreateUDiv(X0, DivCVal);
+      Value *NewMul = Builder.CreateMul(
+          Div, ConstantInt::get(Ty, K - *C));
+      return BinaryOperator::CreateAdd(NewMul, X0);
+    }
+    if (MatchDivMul(Op1, X1, C, K) &&
+        match(Op0, m_OneUse(m_URem(m_Specific(X1), m_APInt(RemC)))) &&
+        *C == *RemC && K.ugt(*C)) {
+      Value *DivCVal = ConstantInt::get(Ty, *C);
+      Value *Div = Builder.CreateUDiv(X1, DivCVal);
+      Value *NewMul = Builder.CreateMul(
+          Div, ConstantInt::get(Ty, K - *C));
+      return BinaryOperator::CreateAdd(NewMul, X1);
+    }
+  }
+
   // (A & C) | (B & D)
   Value *A, *B, *C, *D;
   if (match(Op0, m_And(m_Value(A), m_Value(C))) &&

